oxy_webhelp_navlinks = {"tocId-d30753e20767":{"topics":[{"title":"Azure SQL native backup capabilities","shortdesc":"<p class=\"shortdesc\">Azure provides native backup solutions for Azure SQL workloads, including         Point-in-Time Retention and Long-Term Retention. While these offer foundational protection,         they have certain limitations.<\/p>","href":"saas\/azr_sql_native_backup_capability_2.html","attributes":{"data-id":"azr_sql_native_backup_capability"},"menu":{"hasChildren":false},"tocID":"azr_sql_native_backup_capability-d30753e20768","topics":[]},{"title":"BAK-based backups for Azure SQL Managed Instance","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> uses BAK-based backups to protect Azure SQL Managed Instance         databases using the native SQL Server backup format. This method provides universal schema         compatibility, enterprise scalability, and integrated encryption without requiring         database-level configuration.<\/p>","href":"saas\/azr_sql_mi_bak_backups.html","attributes":{"data-id":"azr_sql_mi_bak_backups"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_bak_backups-d30753e20779","topics":[]},{"title":"Azure SQL native versus Rubrik backups","shortdesc":"<p class=\"shortdesc\">A comparative overview of Azure-native backup policies and Rubrik backups for         Azure SQL workloads.<\/p>","href":"saas\/azr_sql_native_vs_rbk_backups_2.html","attributes":{"data-id":"azr_sql_native_vs_rbk_backups"},"menu":{"hasChildren":false},"tocID":"azr_sql_native_vs_rbk_backups-d30753e20792","topics":[]},{"title":"Independent SLA support for Rubrik and Azure backups","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides independent SLA Domain support for Rubrik backups and         Azure-native backups, enabling both to coexist within the same environment.<\/p>","href":"saas\/azr_sql_independent_sla_support_2.html","attributes":{"data-id":"azr_sql_independent_sla_support"},"menu":{"hasChildren":false},"tocID":"azr_sql_independent_sla_support-d30753e20803","topics":[]},{"title":"Supported Azure SQL backup and recovery types","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects Azure SQL Databases and Managed Instances by supporting         different types of backup and recovery options.<\/p>","href":"saas\/azr_sql_supp_backup_recv_types_2.html","attributes":{"data-id":"azr_sql_supp_backup_recv_types"},"menu":{"hasChildren":false},"tocID":"azr_sql_supp_backup_recv_types-d30753e20816","topics":[]},{"title":"Rubrik backup components for Azure SQL MI","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides cyber-resilient protection for Azure SQL Managed         Instances by leveraging Rubrik Exocompute to orchestrate secure, BAK-based backups that are         logically air-gapped from the source. These backups are stored separately from your source         data and locked with snapshot immutability.<\/p>","href":"saas\/azr_sql_mi_rbk_backup_components.html","attributes":{"data-id":"azr_sql_mi_rbk_backup_components"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_rbk_backup_components-d30753e20829","topics":[]},{"title":"Azure SQL MI Rubrik backup limitations","shortdesc":"<p class=\"shortdesc\">Taking immutable BAK-based backups of Azure SQL Managed Instance databases has         certain limitations.<\/p>","href":"saas\/azr_sql_mi_rbk_backup_limitations.html","attributes":{"data-id":"azr_sql_mi_rbk_backup_limitations"},"menu":{"hasChildren":false},"tocID":"azr_sql_mi_rbk_backup_limitations-d30753e20842","topics":[]}]}};